import * as THREE from "three";

import type { ZenGardenRakeStroke } from "./rake-stroke";

const TEXTURE_RESOLUTION = 1024;
const MAX_STROKES = 16;
const SAMPLES_PER_STROKE = 64;

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = vec4(position.xy, 0.0, 1.0);
  }
`;

const fragmentShader = `
  precision highp float;

  uniform sampler2D gravelColorMap;
  uniform vec2 plainSize;
  uniform float tileSize;

  // Stroke data: x=type (0=none, 1=circle, 2=points), y=width, z=pointCount/radius, w=closed
  uniform vec4 strokeData[${MAX_STROKES}];
  // Circle centers (x, y) for circle strokes
  uniform vec2 circleCenters[${MAX_STROKES}];
  // Sampled points for points-based strokes (flattened: stroke0_point0, stroke0_point1, ...)
  uniform vec2 strokePoints[${MAX_STROKES * SAMPLES_PER_STROKE}];
  uniform int strokeCount;

  varying vec2 vUv;

  float distanceToLineSegment(vec2 p, vec2 a, vec2 b) {
    vec2 ab = b - a;
    float len2 = dot(ab, ab);
    if (len2 < 0.0001) return length(p - a);
    float t = clamp(dot(p - a, ab) / len2, 0.0, 1.0);
    vec2 closest = a + t * ab;
    return length(p - closest);
  }

  float distanceToCircle(vec2 p, vec2 center, float radius) {
    return abs(length(p - center) - radius);
  }

  float distanceToPointsPath(vec2 worldPos, int strokeIndex, int pointCount, bool closed) {
    float minDist = 1000000.0;
    int baseIndex = strokeIndex * ${SAMPLES_PER_STROKE};

    for (int i = 0; i < ${SAMPLES_PER_STROKE - 1}; i++) {
      if (i >= pointCount - 1) break;
      vec2 a = strokePoints[baseIndex + i];
      vec2 b = strokePoints[baseIndex + i + 1];
      float d = distanceToLineSegment(worldPos, a, b);
      minDist = min(minDist, d);
    }

    // Close the path if needed
    if (closed && pointCount > 2) {
      vec2 a = strokePoints[baseIndex + pointCount - 1];
      vec2 b = strokePoints[baseIndex];
      float d = distanceToLineSegment(worldPos, a, b);
      minDist = min(minDist, d);
    }

    return minDist;
  }

  void main() {
    // World position from UV
    vec2 worldPos = (vUv - 0.5) * plainSize;

    // Sample gravel texture using tiled UVs (use fract for proper tiling)
    vec2 tiledUv = worldPos / tileSize;
    vec4 gravelColor = texture2D(gravelColorMap, tiledUv);

    // DEBUG: Uncomment to verify render pipeline
    gl_FragColor = vec4(vUv, 0.0, 1.0); return;

    // Calculate rake stroke influence
    float strokeInfluence = 0.0;

    for (int i = 0; i < ${MAX_STROKES}; i++) {
      if (i >= strokeCount) break;

      vec4 data = strokeData[i];
      float strokeType = data.x;
      float strokeWidth = data.y;

      if (strokeType < 0.5) continue; // type 0 = none

      float dist = 1000000.0;

      if (strokeType < 1.5) {
        // Circle stroke
        float radius = data.z;
        vec2 center = circleCenters[i];
        dist = distanceToCircle(worldPos, center, radius);
      } else {
        // Points stroke
        int pointCount = int(data.z);
        bool closed = data.w > 0.5;
        dist = distanceToPointsPath(worldPos, i, pointCount, closed);
      }

      // Soft edge falloff
      float halfWidth = strokeWidth * 0.5;
      float influence = 1.0 - smoothstep(halfWidth * 0.7, halfWidth, dist);
      strokeInfluence = max(strokeInfluence, influence);
    }

    // Darken where rake strokes are
    vec3 finalColor = gravelColor.rgb * (1.0 - strokeInfluence * 0.3);

    gl_FragColor = vec4(finalColor, 1.0);
  }
`;

export interface PlainTextureGenerator {
  texture: THREE.Texture;
  update(strokes: ZenGardenRakeStroke[]): void;
  dispose(): void;
}

export function createPlainTextureGenerator(
  renderer: THREE.WebGLRenderer,
  plainSize: { x: number; y: number },
  tileSize: number,
  gravelColorMap: THREE.Texture,
): PlainTextureGenerator {
  const renderTarget = new THREE.WebGLRenderTarget(
    TEXTURE_RESOLUTION,
    TEXTURE_RESOLUTION,
    {
      minFilter: THREE.LinearFilter,
      magFilter: THREE.LinearFilter,
      format: THREE.RGBAFormat,
    },
  );

  const geometry = new THREE.PlaneGeometry(2, 2);

  const strokeDataArray = new Float32Array(MAX_STROKES * 4);
  const circleCentersArray = new Float32Array(MAX_STROKES * 2);
  const strokePointsArray = new Float32Array(MAX_STROKES * SAMPLES_PER_STROKE * 2);

  const material = new THREE.ShaderMaterial({
    vertexShader,
    fragmentShader,
    uniforms: {
      gravelColorMap: { value: gravelColorMap },
      plainSize: { value: new THREE.Vector2(plainSize.x, plainSize.y) },
      tileSize: { value: tileSize },
      strokeData: { value: strokeDataArray },
      circleCenters: { value: circleCentersArray },
      strokePoints: { value: strokePointsArray },
      strokeCount: { value: 0 },
    },
  });

  const quad = new THREE.Mesh(geometry, material);
  const scene = new THREE.Scene();
  scene.add(quad);

  const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

  function update(strokes: ZenGardenRakeStroke[]): void {
    const count = Math.min(strokes.length, MAX_STROKES);

    // Reset arrays
    strokeDataArray.fill(0);
    circleCentersArray.fill(0);
    strokePointsArray.fill(0);

    for (let i = 0; i < count; i++) {
      const stroke = strokes[i];
      const encoded = stroke.serialize();
      const path = encoded.path;
      const width = encoded.width;
      const position = stroke.object.position;

      if (path.type === "circle") {
        // type=1 (circle), width, radius, closed=0
        strokeDataArray[i * 4 + 0] = 1;
        strokeDataArray[i * 4 + 1] = width;
        strokeDataArray[i * 4 + 2] = path.radius;
        strokeDataArray[i * 4 + 3] = 0;

        circleCentersArray[i * 2 + 0] = path.center.x + position.x;
        circleCentersArray[i * 2 + 1] = path.center.y + position.y;
      } else {
        // Sample the curve
        const curvePoints = path.points.map(
          (p) => new THREE.Vector3(p.x + position.x, p.y + position.y, 0),
        );

        if (curvePoints.length < 2) {
          strokeDataArray[i * 4 + 0] = 0; // type=none
          continue;
        }

        const curve = new THREE.CatmullRomCurve3(curvePoints, path.closed);
        const sampledPoints = curve.getPoints(SAMPLES_PER_STROKE - 1);

        // type=2 (points), width, pointCount, closed
        strokeDataArray[i * 4 + 0] = 2;
        strokeDataArray[i * 4 + 1] = width;
        strokeDataArray[i * 4 + 2] = sampledPoints.length;
        strokeDataArray[i * 4 + 3] = path.closed ? 1 : 0;

        const baseIndex = i * SAMPLES_PER_STROKE * 2;
        for (let j = 0; j < sampledPoints.length; j++) {
          strokePointsArray[baseIndex + j * 2 + 0] = sampledPoints[j].x;
          strokePointsArray[baseIndex + j * 2 + 1] = sampledPoints[j].y;
        }
      }
    }

    material.uniforms.strokeData.value = strokeDataArray;
    material.uniforms.circleCenters.value = circleCentersArray;
    material.uniforms.strokePoints.value = strokePointsArray;
    material.uniforms.strokeCount.value = count;

    const currentRenderTarget = renderer.getRenderTarget();
    renderer.setRenderTarget(renderTarget);
    renderer.render(scene, camera);
    renderer.setRenderTarget(currentRenderTarget);
  }

  function dispose(): void {
    renderTarget.dispose();
    geometry.dispose();
    material.dispose();
  }

  return {
    texture: renderTarget.texture,
    update,
    dispose,
  };
}
